    @Override public Optional<CitizenRecord> citizen(UUID id){return Optional.ofNullable(citizens.get(id));}
    @Override public Collection<CitizenRecord> citizens(){return List.copyOf(citizens.values());}
    public List<CitizenRecord> citizens(UUID cityId,int limit){return citizenPage(cityId,limit).records();}
    public CitizenPage citizenPage(UUID cityId,int limit){int cap=Math.max(0,limit),examined=0;ArrayList<CitizenRecord>out=new ArrayList<>();boolean truncated=false;for(UUID id:citizenCityIndex.getOrDefault(cityId,new LinkedHashSet<>())){if(examined++>=cap){truncated=true;break;}CitizenRecord record=citizens.get(id);if(record!=null)out.add(record);}return new CitizenPage(List.copyOf(out),truncated,examined);}
    public record CitizenPage(List<CitizenRecord>records,boolean truncated,int examined){public CitizenPage{records=List.copyOf(records);}}
    public CitizenBatch citizenBatch(UUID after,int limit){int cap=Math.max(0,limit);if(cap==0||citizens.isEmpty())return new CitizenBatch(List.of(),after,false,0);ArrayList<CitizenRecord>out=new ArrayList<>(Math.min(cap,citizens.size()));UUID key=after==null?citizens.firstKey():citizens.higherKey(after);boolean wrapped=false;if(key==null){key=citizens.firstKey();wrapped=true;}int examined=0,maximum=Math.min(cap,citizens.size());while(out.size()<maximum){CitizenRecord record=citizens.get(key);if(record!=null)out.add(record);examined++;UUID next=citizens.higherKey(key);if(next==null){wrapped=true;if(out.size()<maximum)next=citizens.firstKey();}key=next;}return new CitizenBatch(List.copyOf(out),out.getLast().id(),wrapped,examined);}
    public record CitizenBatch(List<CitizenRecord>records,UUID nextCursor,boolean wrapped,int examined){public CitizenBatch{records=List.copyOf(records);}}
    public List<CitizenRecord> citizensByName(String displayName,int limit){ArrayList<CitizenRecord>out=new ArrayList<>();for(UUID id:citizenNameIndex.getOrDefault(normalizeName(displayName),new LinkedHashSet<>())){if(out.size()>=Math.max(0,limit))break;CitizenRecord record=citizens.get(id);if(record!=null)out.add(record);}return List.copyOf(out);}
    @Override public void putCitizen(CitizenRecord citizen){if(!readOnly){CitizenRecord previous=citizens.get(citizen.id());if(previous!=null&&citizen.revision()<=previous.revision())throw new IllegalArgumentException("citizen revision must increase");citizens.put(citizen.id(),citizen);if(previous!=null)unindex(previous);index(citizen);setDirty();}}
    @Override public Optional<CitizenLocationRecord>location(UUID id){return Optional.ofNullable(locations.get(id));}
    @Override public boolean updateLocation(CitizenLocationRecord location,long expectedCitizenRevision,long expectedLocationRevision){if(readOnly)return false;CitizenRecord citizen=citizens.get(location.citizenId());CitizenLocationRecord previous=locations.get(location.citizenId());long revision=previous==null?0:previous.revision();if(citizen==null||!citizen.alive()||citizen.revision()!=expectedCitizenRevision||citizen.cityId()==null||!citizen.cityId().equals(location.cityId())||revision!=expectedLocationRevision||location.revision()!=expectedLocationRevision+1)return false;locations.put(location.citizenId(),location);setDirty();return true;}
