    public HouseholdBatch householdBatch(UUID after,int limit){int cap=Math.max(0,limit);if(cap==0||households.isEmpty())return new HouseholdBatch(List.of(),after,false,0);ArrayList<Household>out=new ArrayList<>();UUID key=after==null?households.firstKey():households.higherKey(after);boolean wrapped=false;if(key==null){key=households.firstKey();wrapped=true;}int maximum=Math.min(cap,households.size()),examined=0;while(out.size()<maximum){out.add(households.get(key));examined++;UUID next=households.higherKey(key);if(next==null){wrapped=true;if(out.size()<maximum)next=households.firstKey();}key=next;}return new HouseholdBatch(out,out.getLast().id(),wrapped,examined);}
    public record HouseholdBatch(List<Household>records,UUID nextCursor,boolean wrapped,int examined){public HouseholdBatch{records=List.copyOf(records);}}
    @Override public void putHousehold(Household household){if(!readOnly){Household previous=households.get(household.id());if(previous!=null&&(!previous.cityId().equals(household.cityId())||!previous.partners().equals(household.partners())||!previous.historicalPartners().equals(household.historicalPartners())||household.revision()<=previous.revision()))throw new IllegalArgumentException("invalid household replacement");for(FamilyMemberRef partner:household.partners()){UUID existing=partnerHouseholdIndex.get(partner);if(existing!=null&&!existing.equals(household.id()))throw new IllegalArgumentException("partner already belongs to another household");}for(FamilyMemberRef guardian:household.guardians()){UUID existing=guardianHouseholdIndex.get(guardian);if(existing!=null&&!existing.equals(household.id()))throw new IllegalArgumentException("guardian already belongs to another household");validateFamilyReference(guardian,household.cityId(),household.id());}households.put(household.id(),household);if(previous!=null)unindex(previous);index(household);setDirty();}}
    @Override public boolean createHousehold(Household household,Map<UUID,Long> expected){if(readOnly||households.containsKey(household.id()))return false;Set<FamilyMemberRef>adults=new HashSet<>(household.partners());adults.addAll(household.guardians());for(FamilyMemberRef adult:adults){if(household.partners().contains(adult)&&partnerHouseholdIndex.containsKey(adult)||household.guardians().contains(adult)&&guardianHouseholdIndex.containsKey(adult))return false;if(adult.kind()==FamilyMemberRef.Kind.CITIZEN){CitizenRecord citizen=citizens.get(adult.id());Long revision=expected.get(adult.id());if(citizen==null||revision==null||citizen.revision()!=revision||!citizen.alive()||citizen.householdId()!=null||!household.cityId().equals(citizen.cityId()))return false;}}households.put(household.id(),household);index(household);for(FamilyMemberRef adult:adults)if(adult.kind()==FamilyMemberRef.Kind.CITIZEN){CitizenRecord citizen=citizens.get(adult.id());putCitizen(citizen.withHousehold(household.id()));}setDirty();return true;}
    @Override public boolean recordPartnerDeath(UUID householdId,FamilyMemberRef deceased,long expectedRevision){if(readOnly)return false;Household household=households.get(householdId);if(household==null||household.revision()!=expectedRevision||!household.partners().contains(deceased))return false;Household historical=household.recordPartnerDeath(deceased);unindex(household);households.put(householdId,historical);index(historical);for(FamilyMemberRef member:household.partners())if(!member.equals(deceased)&&member.kind()==FamilyMemberRef.Kind.CITIZEN&&!historical.guardians().contains(member)){CitizenRecord survivor=citizens.get(member.id());if(survivor!=null&&survivor.alive()&&householdId.equals(survivor.householdId()))putCitizen(survivor.withHousehold(null));}setDirty();return true;}
    @Override public Optional<Household>householdForPartner(FamilyMemberRef partner){UUID id=partnerHouseholdIndex.get(partner);return id==null?Optional.empty():Optional.ofNullable(households.get(id));}
    @Override public Optional<Household>householdForGuardian(FamilyMemberRef guardian){UUID id=guardianHouseholdIndex.get(guardian);return id==null?Optional.empty():Optional.ofNullable(households.get(id));}
    @Override public Optional<MarriageProposal>proposal(UUID proposalId){return Optional.ofNullable(proposals.get(proposalId));}
    @Override public Optional<MarriageProposal>activeProposalFor(FamilyMemberRef participant){UUID id=activeProposalIndex.get(participant);return id==null?Optional.empty():Optional.ofNullable(proposals.get(id)).filter(p->p.status()==MarriageProposal.Status.PENDING);}
    @Override public long nextProposalAt(FamilyMemberRef participant){return proposalCooldowns.getOrDefault(participant,0L);}
    @Override public void setNextProposalAt(FamilyMemberRef participant,long tick){if(!readOnly){if(tick<=0)proposalCooldowns.remove(participant);else proposalCooldowns.put(participant,tick);setDirty();}}
    @Override public void putProposal(MarriageProposal proposal){if(!readOnly){MarriageProposal previous=proposals.get(proposal.id());if(previous!=null&&!validProposalTransition(previous,proposal))throw new IllegalArgumentException("invalid proposal replacement");if(proposal.status()==MarriageProposal.Status.PENDING){UUID a=activeProposalIndex.get(proposal.proposer()),b=activeProposalIndex.get(proposal.target());if((a!=null&&!a.equals(proposal.id()))||(b!=null&&!b.equals(proposal.id())))throw new IllegalArgumentException("participant already has active proposal");}if(previous!=null)unindex(previous);proposals.put(proposal.id(),proposal);index(proposal);setDirty();}}
    public ProposalPage proposalPage(FamilyMemberRef participant,int limit){ArrayList<MarriageProposal>out=new ArrayList<>();int cap=Math.max(0,limit),examined=0;for(UUID id:proposalParticipantIndex.getOrDefault(participant,new LinkedHashSet<>())){examined++;if(out.size()>=cap)return new ProposalPage(out,true,examined);MarriageProposal proposal=proposals.get(id);if(proposal!=null)out.add(proposal);}return new ProposalPage(out,false,examined);}
    public record ProposalPage(List<MarriageProposal>records,boolean truncated,int examined){public ProposalPage{records=List.copyOf(records);}}
    public ProposalBatch proposalBatch(UUID after,int limit){int cap=Math.max(0,limit);if(cap==0||proposals.isEmpty())return new ProposalBatch(List.of(),after,false,0);ArrayList<MarriageProposal>out=new ArrayList<>();UUID key=after==null?proposals.firstKey():proposals.higherKey(after);boolean wrapped=false;if(key==null){key=proposals.firstKey();wrapped=true;}int maximum=Math.min(cap,proposals.size()),examined=0;while(out.size()<maximum){out.add(proposals.get(key));examined++;UUID next=proposals.higherKey(key);if(next==null){wrapped=true;if(out.size()<maximum)next=proposals.firstKey();}key=next;}return new ProposalBatch(out,out.getLast().id(),wrapped,examined);}
    public record ProposalBatch(List<MarriageProposal>records,UUID nextCursor,boolean wrapped,int examined){public ProposalBatch{records=List.copyOf(records);}}
    public ProposalDiagnostics proposalDiagnostics(int limit){int cap=Math.max(0,limit),examined=0;EnumMap<MarriageProposal.Status,Integer>counts=new EnumMap<>(MarriageProposal.Status.class);for(MarriageProposal.Status status:MarriageProposal.Status.values())counts.put(status,0);for(MarriageProposal proposal:proposals.values()){if(examined>=cap)break;counts.merge(proposal.status(),1,Integer::sum);examined++;}return new ProposalDiagnostics(counts,examined,proposals.size()>cap);}
    public record ProposalDiagnostics(Map<MarriageProposal.Status,Integer>statusCounts,int examined,boolean truncated){public ProposalDiagnostics{statusCounts=Map.copyOf(statusCounts);}}
    public void removeProposal(UUID id){if(readOnly)return;MarriageProposal removed=proposals.remove(id);if(removed!=null){unindex(removed);setDirty();}}
