    public boolean createReproductionConsent(ReproductionConsent consent,int cap){if(readOnly||reproductionConsents.size()>=Math.max(0,cap)||reproductionConsents.containsKey(consent.id())||activeReproductionConsentIndex.containsKey(consent.proposer())||activeReproductionConsentIndex.containsKey(consent.target()))return false;reproductionConsents.put(consent.id(),consent);activeReproductionConsentIndex.put(consent.proposer(),consent.id());activeReproductionConsentIndex.put(consent.target(),consent.id());setDirty();return true;}
    public boolean removeReproductionConsent(UUID id,long expectedRevision){if(readOnly)return false;ReproductionConsent consent=reproductionConsents.get(id);if(consent==null||consent.revision()!=expectedRevision)return false;reproductionConsents.remove(id);activeReproductionConsentIndex.remove(consent.proposer(),id);activeReproductionConsentIndex.remove(consent.target(),id);setDirty();return true;}
    public int reproductionConsentCount(){return reproductionConsents.size();}
    public PregnancyBatch pregnancyBatch(UUID after,int limit){int cap=Math.max(0,limit);if(cap==0||pregnancies.isEmpty())return new PregnancyBatch(List.of(),after,false,0);ArrayList<PregnancyRecord>out=new ArrayList<>();UUID key=after==null?pregnancies.firstKey():pregnancies.higherKey(after);boolean wrapped=false;if(key==null){key=pregnancies.firstKey();wrapped=true;}int maximum=Math.min(cap,pregnancies.size()),examined=0;while(out.size()<maximum){out.add(pregnancies.get(key));examined++;UUID next=pregnancies.higherKey(key);if(next==null){wrapped=true;if(out.size()<maximum)next=pregnancies.firstKey();}key=next;}return new PregnancyBatch(out,out.getLast().id(),wrapped,examined);}
    public record PregnancyBatch(List<PregnancyRecord>records,UUID nextCursor,boolean wrapped,int examined){public PregnancyBatch{records=List.copyOf(records);}}
    public void putPregnancy(PregnancyRecord record){if(readOnly)return;for(FamilyMemberRef parent:record.parents())validateFamilyReference(parent,record.cityId(),null);if(gender(record.gestationalParent())!=Gender.FEMALE||genders(record.parents()).size()!=2)throw new IllegalArgumentException("invalid pregnancy genders");PregnancyRecord previous=pregnancies.get(record.id());if(previous!=null&&(!samePregnancyIdentity(previous,record)||record.revision()!=previous.revision()+1))throw new IllegalArgumentException("invalid pregnancy replacement");UUID active=activePregnancyIndex.get(record.gestationalParent());if(active!=null&&!active.equals(record.id()))throw new IllegalArgumentException("gestational parent already pregnant");pregnancies.put(record.id(),record);activePregnancyIndex.put(record.gestationalParent(),record.id());setDirty();}
    @Override public boolean createPregnancy(PregnancyRecord record,Map<FamilyMemberRef,Long>expectedRevisions,int pregnancyCapacity,long now){if(readOnly||pregnancies.size()>=Math.max(0,pregnancyCapacity)||pregnancies.containsKey(record.id())||activePregnancyIndex.containsKey(record.gestationalParent()))return false;try{for(FamilyMemberRef parent:record.parents()){validateFamilyReference(parent,record.cityId(),null);Long expected=expectedRevisions.get(parent);if(expected==null||memberRevision(parent)!=expected||nextReproductionAt(parent)>now)return false;if(parent.kind()==FamilyMemberRef.Kind.CITIZEN&&!citizens.get(parent.id()).alive())return false;}if(gender(record.gestationalParent())!=Gender.FEMALE||genders(record.parents()).size()!=2)return false;}catch(RuntimeException exception){return false;}pregnancies.put(record.id(),record);activePregnancyIndex.put(record.gestationalParent(),record.id());setDirty();return true;}
    public void removePregnancy(UUID id,long expectedRevision){if(readOnly)return;PregnancyRecord record=pregnancies.get(id);if(record==null||record.revision()!=expectedRevision)throw new IllegalArgumentException("stale pregnancy removal");pregnancies.remove(id);activePregnancyIndex.remove(record.gestationalParent(),id);setDirty();}
    @Override public Optional<ParentageRecord>parentage(UUID childId){return Optional.ofNullable(parentageByChild.get(childId));}
    @Override public Collection<ParentageRecord>parentageForParent(FamilyMemberRef parent,int limit){ArrayList<ParentageRecord>out=new ArrayList<>();for(UUID childId:childrenByParent.getOrDefault(parent,new LinkedHashSet<>())){if(out.size()>=Math.max(0,limit))break;ParentageRecord record=parentageByChild.get(childId);if(record!=null)out.add(record);}return List.copyOf(out);}
    public void putParentage(ParentageRecord record){if(readOnly)return;CitizenRecord child=citizens.get(record.childId());if(child==null||!record.cityId().equals(child.cityId()))throw new IllegalArgumentException("missing parentage child");for(FamilyMemberRef parent:record.parents())validateFamilyReference(parent,record.cityId(),null);ParentageRecord previous=parentageByChild.get(record.childId());if(previous!=null&&(!sameParentageIdentity(previous,record)||record.revision()!=previous.revision()+1))throw new IllegalArgumentException("invalid parentage replacement");if(previous!=null)unindex(previous);parentageByChild.put(record.childId(),record);index(record);setDirty();}
