    public OrphanPage orphanPage(UUID cityId,int limit){int cap=Math.max(0,limit),examined=0;ArrayList<OrphanRecord>out=new ArrayList<>();boolean truncated=false;for(UUID id:orphanCityIndex.getOrDefault(cityId,new LinkedHashSet<>())){if(examined++>=cap){truncated=true;break;}OrphanRecord record=orphans.get(id);if(record!=null)out.add(record);}return new OrphanPage(out,truncated,examined);}
    public record OrphanPage(List<OrphanRecord>records,boolean truncated,int examined){public OrphanPage{records=List.copyOf(records);}}
    public OrphanBatch orphanBatch(UUID after,int limit){int cap=Math.max(0,limit);if(cap==0||orphans.isEmpty())return new OrphanBatch(List.of(),after,false,0);ArrayList<OrphanRecord>out=new ArrayList<>();UUID key=after==null?orphans.firstKey():orphans.higherKey(after);boolean wrapped=false;if(key==null){key=orphans.firstKey();wrapped=true;}int maximum=Math.min(cap,orphans.size()),examined=0;while(out.size()<maximum){out.add(orphans.get(key));examined++;UUID next=orphans.higherKey(key);if(next==null){wrapped=true;if(out.size()<maximum)next=orphans.firstKey();}key=next;}return new OrphanBatch(out,out.getLast().childId(),wrapped,examined);}
    public record OrphanBatch(List<OrphanRecord>records,UUID nextCursor,boolean wrapped,int examined){public OrphanBatch{records=List.copyOf(records);}}
    @Override public void putOrphan(OrphanRecord record){if(readOnly)return;CitizenRecord child=citizens.get(record.childId());if(child==null||!child.alive()||!record.cityId().equals(child.cityId())||!parentageByChild.containsKey(record.childId()))throw new IllegalArgumentException("invalid orphan child");OrphanRecord previous=orphans.get(record.childId());if(previous!=null&&(!sameOrphanIdentity(previous,record)||record.revision()!=previous.revision()+1))throw new IllegalArgumentException("invalid orphan replacement");orphans.put(record.childId(),record);if(previous!=null)removeIndex(orphanCityIndex,previous.cityId(),previous.childId());orphanCityIndex.computeIfAbsent(record.cityId(),ignored->new LinkedHashSet<>()).add(record.childId());setDirty();}
    public Optional<AdoptionConsent>adoptionConsent(UUID id){return Optional.ofNullable(adoptionConsents.get(id));}
    public Optional<AdoptionConsent>adoptionConsentForChild(UUID childId){UUID id=adoptionConsentByChild.get(childId);return id==null?Optional.empty():Optional.ofNullable(adoptionConsents.get(id));}
    public List<AdoptionConsent>adoptionConsentsForPlayer(UUID player,int limit){ArrayList<AdoptionConsent>out=new ArrayList<>();for(UUID id:adoptionConsentsByPlayer.getOrDefault(player,new LinkedHashSet<>())){if(out.size()>=Math.max(0,limit))break;AdoptionConsent consent=adoptionConsents.get(id);if(consent!=null)out.add(consent);}return List.copyOf(out);}
    public List<AdoptionConsent>adoptionConsentsForCity(UUID city,int limit){ArrayList<AdoptionConsent>out=new ArrayList<>();for(AdoptionConsent consent:adoptionConsents.values()){if(out.size()>=Math.max(0,limit))break;if(consent.cityId().equals(city))out.add(consent);}return List.copyOf(out);}
    public boolean createAdoptionConsent(AdoptionConsent consent,int cap){if(readOnly||adoptionConsents.size()>=Math.max(0,cap)||adoptionConsents.containsKey(consent.id())||adoptionConsentByChild.containsKey(consent.childId())||!orphans.containsKey(consent.childId()))return false;for(UUID player:consent.requiredPlayers())if(!profiles.containsKey(player))return false;adoptionConsents.put(consent.id(),consent);index(consent);setDirty();return true;}
    public boolean updateAdoptionConsent(AdoptionConsent consent,long expectedRevision){AdoptionConsent current=adoptionConsents.get(consent.id());if(readOnly||current==null||current.revision()!=expectedRevision||consent.revision()!=expectedRevision+1||!sameAdoptionConsentIdentity(current,consent)||!consent.confirmedPlayers().containsAll(current.confirmedPlayers()))return false;adoptionConsents.put(consent.id(),consent);setDirty();return true;}
    public boolean removeAdoptionConsent(UUID id,long expectedRevision){AdoptionConsent current=adoptionConsents.get(id);if(readOnly||current==null||current.revision()!=expectedRevision)return false;adoptionConsents.remove(id);unindex(current);setDirty();return true;}
    public AdoptionConsentBatch adoptionConsentBatch(UUID after,int limit){int cap=Math.max(0,limit);if(cap==0||adoptionConsents.isEmpty())return new AdoptionConsentBatch(List.of(),after,false);ArrayList<AdoptionConsent>out=new ArrayList<>();UUID key=after==null?adoptionConsents.firstKey():adoptionConsents.higherKey(after);boolean wrapped=false;if(key==null){key=adoptionConsents.firstKey();wrapped=true;}int maximum=Math.min(cap,adoptionConsents.size());while(out.size()<maximum){out.add(adoptionConsents.get(key));UUID next=adoptionConsents.higherKey(key);if(next==null){wrapped=true;if(out.size()<maximum)next=adoptionConsents.firstKey();}key=next;}return new AdoptionConsentBatch(out,out.getLast().id(),wrapped);}
