    @Override public boolean commitAdoption(OrphanRecord expectedOrphan,long expectedChildRevision,Household adoptive,long expectedAdoptiveRevision,Household origin,Household originAfter,CitizenRecord childAfter,Map<UUID,Long>guardianRevisions,Set<UUID>confirmedPlayers,int childCapacity){
        if(readOnly||expectedOrphan==null||adoptive==null||childAfter==null||adoptive.children().size()>Math.max(1,childCapacity)||!adoptive.children().contains(childAfter.id())||!adoptive.id().equals(childAfter.householdId())||!adoptive.cityId().equals(childAfter.cityId())||adoptive.guardians().isEmpty())return false;
        OrphanRecord currentOrphan=orphans.get(expectedOrphan.childId());CitizenRecord child=citizens.get(expectedOrphan.childId());if(!expectedOrphan.equals(currentOrphan)||child==null||!child.alive()||child.revision()!=expectedChildRevision||!child.cityId().equals(adoptive.cityId())||childAfter.revision()<=child.revision())return false;
        Household currentAdoptive=households.get(adoptive.id());if(currentAdoptive==null){if(expectedAdoptiveRevision!=0||adoptive.revision()!=1)return false;}else if(currentAdoptive.revision()!=expectedAdoptiveRevision||adoptive.revision()!=expectedAdoptiveRevision+1||!currentAdoptive.cityId().equals(adoptive.cityId()))return false;
        Household currentOrigin=origin==null?null:households.get(origin.id());if(origin!=null&&(currentOrigin==null||!currentOrigin.equals(origin)||originAfter==null||originAfter.revision()!=origin.revision()+1||originAfter.children().contains(child.id())))return false;
        Map<UUID,CitizenRecord>guardianUpdates=new HashMap<>();try{for(FamilyMemberRef guardian:adoptive.guardians()){UUID indexed=guardianHouseholdIndex.get(guardian);if(indexed!=null&&!indexed.equals(adoptive.id()))return false;if(guardian.kind()==FamilyMemberRef.Kind.PLAYER){if(!profiles.containsKey(guardian.id())||!confirmedPlayers.contains(guardian.id()))return false;continue;}CitizenRecord adult=citizens.get(guardian.id());Long revision=guardianRevisions.get(guardian.id());if(adult==null||revision==null||adult.revision()!=revision||!adult.alive()||!adult.cityId().equals(adoptive.cityId()))return false;if(adult.householdId()==null)guardianUpdates.put(adult.id(),adult.withHousehold(adoptive.id()));else if(!adult.householdId().equals(adoptive.id()))return false;}}catch(RuntimeException exception){return false;}
        if(currentOrigin!=null){unindex(currentOrigin);households.put(originAfter.id(),originAfter);index(originAfter);}if(currentAdoptive!=null)unindex(currentAdoptive);households.put(adoptive.id(),adoptive);index(adoptive);for(CitizenRecord update:guardianUpdates.values()){CitizenRecord old=citizens.put(update.id(),update);unindex(old);index(update);}unindex(child);citizens.put(child.id(),childAfter);index(childAfter);OrphanRecord removed=orphans.remove(child.id());if(removed!=null)removeIndex(orphanCityIndex,removed.cityId(),removed.childId());setDirty();return true;
    }
    public void removeOrphan(UUID childId,long expectedRevision){if(readOnly)return;OrphanRecord record=orphans.get(childId);if(record==null||record.revision()!=expectedRevision)throw new IllegalArgumentException("stale orphan removal");orphans.remove(childId);removeIndex(orphanCityIndex,record.cityId(),record.childId());setDirty();}
    public long nextReproductionAt(FamilyMemberRef member){return reproductionCooldowns.getOrDefault(member,0L);}
    public void setNextReproductionAt(FamilyMemberRef member,long tick){if(readOnly)return;if(tick<=0)reproductionCooldowns.remove(member);else reproductionCooldowns.put(member,tick);setDirty();}
    @Override public boolean commitBirth(PregnancyRecord expectedPregnancy,CitizenRecord child,ParentageRecord parentage,Household household,Map<FamilyMemberRef,Long>expectedParentRevisions,long cooldownUntil,int householdChildCapacity){
        if(readOnly||expectedPregnancy==null||child==null||parentage==null||household==null)return false;
        PregnancyRecord currentPregnancy=pregnancies.get(expectedPregnancy.id());
        if(!expectedPregnancy.equals(currentPregnancy)||citizens.containsKey(child.id())||parentageByChild.containsKey(child.id())||orphans.containsKey(child.id())
                ||!child.id().equals(parentage.childId())||!child.cityId().equals(expectedPregnancy.cityId())||!child.cityId().equals(parentage.cityId())
                ||!parentage.parents().equals(expectedPregnancy.parents())||!household.cityId().equals(child.cityId())||!household.children().contains(child.id())
                ||!household.id().equals(child.householdId())||household.children().size()>Math.max(0,householdChildCapacity)||household.guardians().isEmpty())return false;
        for(FamilyMemberRef parent:expectedPregnancy.parents()){Long revision=expectedParentRevisions.get(parent);if(revision==null||memberRevision(parent)!=revision)return false;}
        if(expectedPregnancy.gestationalParent().kind()==FamilyMemberRef.Kind.CITIZEN&&!citizens.get(expectedPregnancy.gestationalParent().id()).alive())return false;
        Household previous=households.get(household.id());
        if(previous==null){if(household.revision()!=1)return false;}
        else if(!previous.cityId().equals(household.cityId())||!previous.partners().equals(household.partners())||!previous.historicalPartners().equals(household.historicalPartners())||household.revision()!=previous.revision()+1)return false;
        Map<UUID,CitizenRecord>adultUpdates=new HashMap<>();
        try{
            for(FamilyMemberRef guardian:household.guardians()){
                validateFamilyReference(guardian,household.cityId(),previous==null?null:household.id());
                UUID indexed=guardianHouseholdIndex.get(guardian);if(indexed!=null&&!indexed.equals(household.id()))return false;
                if(guardian.kind()==FamilyMemberRef.Kind.CITIZEN){CitizenRecord adult=citizens.get(guardian.id());if(adult.householdId()==null){Long expected=expectedParentRevisions.get(guardian);if(expected==null||adult.revision()!=expected)return false;adultUpdates.put(adult.id(),adult.withHousehold(household.id()));}else if(!household.id().equals(adult.householdId()))return false;}
            }
        }catch(RuntimeException exception){return false;}
        if(previous!=null)unindex(previous);households.put(household.id(),household);index(household);
        for(CitizenRecord update:adultUpdates.values()){CitizenRecord old=citizens.put(update.id(),update);if(old!=null)unindex(old);index(update);}
        citizens.put(child.id(),child);index(child);parentageByChild.put(child.id(),parentage);index(parentage);
        pregnancies.remove(currentPregnancy.id());activePregnancyIndex.remove(currentPregnancy.gestationalParent(),currentPregnancy.id());
        for(FamilyMemberRef parent:currentPregnancy.parents())reproductionCooldowns.put(parent,Math.max(0,cooldownUntil));
        setDirty();return true;
    }
