    public MigrationBatch migrationBatch(UUID after,int limit){int cap=Math.max(0,limit);if(cap==0||migrations.isEmpty())return new MigrationBatch(List.of(),after,false,0);ArrayList<MigrationGroupRecord>out=new ArrayList<>();UUID key=after==null?migrations.firstKey():migrations.higherKey(after);boolean wrapped=false;if(key==null){key=migrations.firstKey();wrapped=true;}int maximum=Math.min(cap,migrations.size()),examined=0;UUID last=after;while(examined++<maximum){MigrationGroupRecord record=migrations.get(key);last=key;if(record.state()!=MigrationGroupRecord.State.REGIONAL_POOL)out.add(record);UUID next=migrations.higherKey(key);if(next==null){wrapped=true;if(examined<maximum)next=migrations.firstKey();}key=next;}return new MigrationBatch(List.copyOf(out),last,wrapped,examined-1);}
