    @Override public int activeMigrationCount(){return migrations.size();}
    @Override public boolean createMigration(MigrationGroupRecord group,Collection<CitizenRecord>members,int activeCap){
        if(readOnly||migrations.size()>=Math.max(0,activeCap)||migrations.containsKey(group.id())||members.size()!=group.members().size())return false;
        Map<UUID,CitizenRecord>created=new HashMap<>();for(CitizenRecord citizen:members){if(!group.members().contains(citizen.id())||citizen.cityId()!=null||citizen.householdId()!=null||citizens.containsKey(citizen.id())||migrationByMember.containsKey(citizen.id())||created.put(citizen.id(),citizen)!=null)return false;}
        if(!created.keySet().equals(group.members()))return false;migrations.put(group.id(),group);index(group);for(CitizenRecord citizen:created.values()){citizens.put(citizen.id(),citizen);index(citizen);}setDirty();return true;
    }
    @Override public boolean beginOutMigration(MigrationGroupRecord group,Household household,Map<UUID,Long>expectedCitizenRevisions,int activeCap){
        if(readOnly||group==null||group.state()!=MigrationGroupRecord.State.DEPARTING||migrations.size()>=Math.max(0,activeCap)||migrations.containsKey(group.id())||!expectedCitizenRevisions.keySet().equals(group.members()))return false;
        Household currentHousehold=household==null?null:households.get(household.id());if(household!=null&&!household.equals(currentHousehold))return false;Set<UUID>expectedMembers=new HashSet<>();if(currentHousehold!=null){for(FamilyMemberRef adult:currentHousehold.partners())if(adult.kind()==FamilyMemberRef.Kind.CITIZEN)expectedMembers.add(adult.id());for(FamilyMemberRef adult:currentHousehold.guardians())if(adult.kind()==FamilyMemberRef.Kind.CITIZEN)expectedMembers.add(adult.id());expectedMembers.addAll(currentHousehold.children());if(!expectedMembers.equals(group.members())||!currentHousehold.children().equals(group.children()))return false;}else if(group.members().size()!=1)return false;
        for(UUID id:group.members()){CitizenRecord citizen=citizens.get(id);Long revision=expectedCitizenRevisions.get(id);FamilyMemberRef ref=FamilyMemberRef.citizen(id);if(citizen==null||revision==null||citizen.revision()!=revision||!citizen.alive()||!group.targetCityId().equals(citizen.cityId())||migrationByMember.containsKey(id)||citizen.runtimeState()==CitizenRuntimeState.LOCKED||activeProposalIndex.containsKey(ref)||activeReproductionConsentIndex.containsKey(ref)||activePregnancyIndex.containsKey(ref)||orphans.containsKey(id))return false;for(PregnancyRecord pregnancy:pregnancies.values())if(pregnancy.parents().contains(ref))return false;for(AdoptionConsent consent:adoptionConsents.values())if(consent.guardians().contains(ref)||consent.childId().equals(id))return false;}
        if(currentHousehold!=null){unindex(currentHousehold);households.remove(currentHousehold.id());}migrations.put(group.id(),group);index(group);for(UUID id:group.members()){CitizenRecord old=citizens.get(id),departing=old.leaveCity();unindex(old);citizens.put(id,departing);index(departing);locations.remove(id);}setDirty();return true;
    }
    @Override public boolean updateMigration(MigrationGroupRecord group,long expectedRevision){MigrationGroupRecord current=migrations.get(group.id());boolean reactivation=current!=null&&current.state()==MigrationGroupRecord.State.REGIONAL_POOL&&group.state()==MigrationGroupRecord.State.APPROACHING&&sameMigrationFamily(current,group);if(readOnly||current==null||current.revision()!=expectedRevision||group.revision()!=expectedRevision+1||!reactivation&&!sameMigrationIdentity(current,group))return false;unindex(current);migrations.put(group.id(),group);index(group);setDirty();return true;}
    @Override public boolean settleMigration(MigrationGroupRecord group,long expectedRevision,UUID residenceId,long settledAt){
        MigrationGroupRecord current=migrations.get(group.id());if(readOnly||current==null||current.revision()!=expectedRevision||current.state()!=MigrationGroupRecord.State.APPLIED||settledAt<0)return false;
        Map<UUID,CitizenRecord>source=new HashMap<>();for(UUID id:current.members()){CitizenRecord citizen=citizens.get(id);if(citizen==null||citizen.cityId()!=null||citizen.householdId()!=null||!citizen.alive())return false;source.put(id,citizen);}
        UUID householdId=current.partners().isEmpty()&&current.children().isEmpty()?null:current.id();if(householdId!=null&&households.containsKey(householdId))return false;
        Set<FamilyMemberRef>partners=current.partners().stream().map(FamilyMemberRef::citizen).collect(java.util.stream.Collectors.toSet());Set<FamilyMemberRef>guardians=current.guardians().stream().map(FamilyMemberRef::citizen).collect(java.util.stream.Collectors.toSet());
        Household household=householdId==null?null:new Household(householdId,current.targetCityId(),partners,Set.of(),guardians,current.children(),residenceId,50,residenceId==null?0:100,1);
        if(household!=null){households.put(household.id(),household);index(household);}
        for(CitizenRecord citizen:source.values()){CitizenRecord settled=citizen.settle(current.targetCityId(),householdId,residenceId);citizens.put(citizen.id(),settled);unindex(citizen);index(settled);migrationOrigins.put(citizen.id(),new MigrationOriginRecord(citizen.id(),current.id(),current.targetCityId(),current.dimension(),current.originPos(),settledAt,1));locations.put(citizen.id(),new CitizenLocationRecord(citizen.id(),current.targetCityId(),current.dimension(),current.memberPositions().get(citizen.id()),settledAt,1));}
        for(UUID childId:current.children())if(!parentageByChild.containsKey(childId)){Set<FamilyMemberRef>parents=partners.isEmpty()?guardians:partners;ParentageRecord parentage=new ParentageRecord(childId,current.targetCityId(),parents,Math.max(0,settledAt-source.get(childId).ageTicks()),false,ParentageRecord.Source.MIGRATION_WITH_SOURCE,1);parentageByChild.put(childId,parentage);index(parentage);}
        unindex(current);migrations.remove(current.id());setDirty();return true;
    }
    @Override public boolean poolDepartedMigration(MigrationGroupRecord group,long expectedRevision){MigrationGroupRecord current=migrations.get(group.id());if(readOnly||current==null||current.revision()!=expectedRevision||current.state()!=MigrationGroupRecord.State.DEPARTING)return false;for(UUID id:current.members()){CitizenRecord citizen=citizens.get(id);if(citizen==null||citizen.cityId()!=null)return false;}MigrationGroupRecord pooled=current.pooled();unindex(current);migrations.put(current.id(),pooled);index(pooled);setDirty();return true;}
    public List<MigrationGroupRecord>regionalPool(String dimension,int limit){ArrayList<MigrationGroupRecord>out=new ArrayList<>();int examined=0,cap=Math.max(0,limit);for(MigrationGroupRecord group:migrations.values()){if(examined++>=cap)break;if(group.state()==MigrationGroupRecord.State.REGIONAL_POOL&&group.dimension().equals(dimension))out.add(group);}return List.copyOf(out);}
