    private static CompoundTag saveCitizen(CitizenRecord c){CompoundTag t=new CompoundTag();t.putString("Id",c.id().toString());t.putString("GivenName",c.givenName());t.putString("FamilyName",c.familyName());t.putString("Race",c.race().name());t.putString("Appearance",c.appearanceKey());t.putString("Gender",c.gender().name());t.putLong("AgeTicks",c.ageTicks());t.putLong("LastAgeUpdateTick",c.lastAgeUpdateTick());t.putInt("LifespanYears",c.lifespanYears());t.putLong("DiedAtTick",c.diedAtTick());t.putString("DeathCause",c.deathCause().name());putUuid(t,"CityId",c.cityId());putUuid(t,"HouseholdId",c.householdId());putUuid(t,"ResidenceId",c.residenceId());putUuid(t,"WorkBuildingId",c.workBuildingId());t.putString("Profession",c.profession());t.putInt("Health",c.health());CompoundTag needs=new CompoundTag();needs.putInt("Food",c.needs().food());needs.putInt("Safety",c.needs().safety());needs.putInt("Rest",c.needs().rest());needs.putInt("Social",c.needs().social());t.put("Needs",needs);ListTag skills=new ListTag();c.skills().forEach((key,value)->{CompoundTag skill=new CompoundTag();skill.putString("Key",key);skill.putInt("Value",value);skills.add(skill);});t.put("Skills",skills);t.put("Relationships",uuidList(c.relationships()));t.putDouble("SettlementWillingness",c.settlementWillingness());t.putDouble("MigrationWillingness",c.migrationWillingness());t.putString("RuntimeState",c.runtimeState().name());t.putLong("RuntimeLockUntilTick",c.runtimeLockUntilTick());t.putLong("Revision",c.revision());return t;}
