    private static CompoundTag saveHousehold(Household h){CompoundTag t=new CompoundTag();t.putString("Id",h.id().toString());t.putString("CityId",h.cityId().toString());t.put("Partners",familyList(h.partners()));t.put("HistoricalPartners",familyList(h.historicalPartners()));t.put("Guardians",familyList(h.guardians()));t.put("Children",uuidList(h.children()));putUuid(t,"ResidenceId",h.residenceId());t.putInt("FoodCoverage",h.foodCoverage());t.putInt("HousingCoverage",h.housingCoverage());t.putLong("Revision",h.revision());return t;}
